function getLicenseType(license: string): undefined | number {
  const licenseType = (() => {
    if (license === 'None') {
      return 1;
    }
    if (license === 'UNLICENSED') {
      return 2;
    }
    if (license === 'MIT') {
      return 3;
    }
    if (license === 'GPL-2.0') {
      return 4;
    }
    if (license === 'GPL-3.0') {
      return 5;
    }
    if (license === 'LGPL-2.1') {
      return 6;
    }
    if (license === 'LGPL-3.0') {
      return 7;
    }
    if (license === 'BSD-2-Clause') {
      return 8;
    }
    if (license === 'BSD-3-Clause') {
      return 9;
    }
    if (license === 'MPL-2.0') {
      return 10;
    }
    if (license === 'OSL-3.0') {
      return 11;
    }
    if (license === 'Apache-2.0') {
      return 12;
    }
    if (license === 'AGPL-3.0') {
      return 13;
    }
    if (license === 'BUSL-1.1') {
      return 14;
    }
  })();
  return licenseType;
}
